template <typename T>
class Trie01Vector {
private:
    struct TrieNode {
        array<int, 2> children;
        int cnt;
        TrieNode() : children{ 0, 0 }, cnt(0) {}
    };

    vector<TrieNode> tr;
    int newNode() {
        tr.push_back(TrieNode());
        return ++nodeCnt;
    }

    int MAX;
    int nodeCnt = 1;
    int root = 1;

public:
    Trie01Vector(int MAX) :MAX(MAX), tr(2) {}

    void insert(T num) {
        int now = root;
        tr[now].cnt++;
        for (int i = MAX; i >= 0; i--) {
            bool bit = (num >> i) & 1;
            if (not tr[now].children[bit]) {
                int tmp = newNode();
                tr[now].children[bit] = tmp;
            }
            now = tr[now].children[bit];
            tr[now].cnt++;
        }
    }

    int dfs(int now, int i, T pre) {
        var to = array<int, 2>{ tr[now].children[0], tr[now].children[1] };
        if (to[0] and to[1]) {
            if (tr[to[0]].cnt >= 2 and tr[to[1]].cnt >= 2)
                return max(dfs(to[0], i - 1, pre), dfs(to[1], i - 1, pre + (1ll << i))) + 1;
            else if (tr[to[1]].cnt == 1)
                return dfs(to[0], i - 1, pre) + 1;
          	else if (tr[to[0]].cnt == 1)
              	return dfs(to[1], i - 1, pre + (1ll << i)) + 1;
            else
                return 2;
        }
        else if (to[0]) return dfs(to[0], i - 1, pre);
        else if (to[1]) return dfs(to[1], i - 1, pre + (1ll << i));
        else return 1;
    }

    int dfs() {
        return dfs(root, MAX, 0);
    }
};
